// ═══════════════════════════════════════════════════════════════════
//  PHISHING TRIAGE ENGINE
//  EmlParser result → artifacts → routed & batched enrichment
//  → aggregated verdict + email metadata (ticket-ready)
// ═══════════════════════════════════════════════════════════════════
const T0 = Date.now();

const CORTEX = 'http://10.10.10.10:9001';
const AUTH   = 'Bearer ' + 'PASTE_FULL_MDR_ADMIN_KEY';   
const TLP    = 2;

const EMLPARSER_NAME = 'EmlParser_2_1';

const REGISTRY = {
  AbuseIPDB:   { id: '7949e6404f6a75c2c8d2661dbf5656c8' },
  VirusTotal:  { id: 'd911cd666346650b3d3f9b99998b0d42' },
  URLhaus:     { id: '2983c453fe359bab2e3e0e67563d47d6' },
  Pulsedive:   { id: 'a1ea4f51edd0e4cc86badab86cafb3ce' },
  GoogleDNS:   { id: '1f039c328b0c7f1434a1c5e741d2e4d6' },
  EmailRep:    { id: 'a42163133c48fa8c5f07617cb0b6bd8e' },
  AbuseFinder: { id: '0647e7d7ef7d7806ac3c095070a18e28' },
  Urlscan:     { id: '0d73227df4242d7811c574a0019c0817', slow: true },
};

const ROUTING = {
  ip:     ['AbuseIPDB', 'VirusTotal', 'Pulsedive'],
  domain: ['VirusTotal', 'URLhaus', 'Pulsedive', 'GoogleDNS'],
  fqdn:   ['VirusTotal', 'URLhaus', 'GoogleDNS'],
  url:    ['VirusTotal', 'URLhaus', 'Urlscan'],
  hash:   ['VirusTotal', 'URLhaus'],
  mail:   ['EmailRep', 'AbuseFinder'],
};

const CONCURRENCY             = 3;
const MAX_ANALYZERS_PER_OBS   = 4;
const INCLUDE_SLOW            = false;
const PER_ANALYZER_TIMEOUT_MS = 40000;
const EML_TIMEOUT_MS          = 60000;
const POLL_SCHEDULE_MS        = [800, 1200, 1500, 2000, 2500, 3000];
const POLL_FALLBACK_MS        = 3500;

const http  = this.helpers.httpRequest.bind(this);
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const jsonHeaders = { Authorization: AUTH, 'Content-Type': 'application/json', Accept: 'application/json' };

const LEVEL_RANK = { info: 0, safe: 1, suspicious: 2, malicious: 3 };
const RANK_LEVEL = ['info', 'safe', 'suspicious', 'malicious'];
// Some analyzers colour informational metrics with a severity level:
// VT "43 resolution(s)", EmailRep "References", GoogleDNS record counts.
// Those are context, not verdicts — ranking them turns every lookup malicious.
const NON_VERDICT = [/resolution\(s\)/i, /record/i, /reference/i];
const bearsVerdict = (t) => {
  const v = String(t.val !== undefined ? t.val : (t.value !== undefined ? t.value : ''));
  return !NON_VERDICT.some(re => re.test(v));
};;

const errText = (e) => {
  const d = e && e.response && e.response.data;
  if (d) return typeof d === 'string' ? d.slice(0, 300) : JSON.stringify(d).slice(0, 300);
  return String((e && e.message) || e);
};

async function jobStatus(id) {
  const r = await http({ method: 'GET', url: `${CORTEX}/api/job/${id}`, headers: jsonHeaders, json: true });
  return r.status;
}

async function jobReport(id) {
  const r = await http({ method: 'GET', url: `${CORTEX}/api/job/${id}/report`, headers: jsonHeaders, json: true });
  let rep = r.report || {};
  if (typeof rep === 'string') rep = JSON.parse(rep);
  return rep;
}

async function poll(id, budgetMs) {
  const start = Date.now();
  let i = 0;
  while (Date.now() - start < budgetMs) {
    try {
      const s = await jobStatus(id);
      if (s === 'Success' || s === 'Failure') return s;
    } catch (e) { /* transient */ }
    await sleep(POLL_SCHEDULE_MS[i] ?? POLL_FALLBACK_MS);
    i++;
  }
  return 'Timeout';
}

// ── STEP 1: find the EmlParser job (input-shape independent) ───────
// Prefer an id handed over by the upload node; otherwise ask Cortex
// for its most recent EmlParser job — the one we just submitted.
let emlJobId = null;
try {
  const inp = $input.first().json;
  if (inp && typeof inp.id === 'string' && inp.id.length > 5) emlJobId = inp.id;
} catch (e) { /* no usable input */ }

if (!emlJobId) {
  const recent = await http({ method: 'GET', url: `${CORTEX}/api/job?range=0-9`, headers: jsonHeaders, json: true });
  const list = Array.isArray(recent) ? recent : [];
  const hit = list.find(j => j.workerDefinitionId === EMLPARSER_NAME || j.workerName === EMLPARSER_NAME);
  if (!hit) throw new Error('No recent EmlParser job found in Cortex — did the upload node run?');
  emlJobId = hit.id;
}

const emlStatus = await poll(emlJobId, EML_TIMEOUT_MS);
if (emlStatus !== 'Success') throw new Error(`EmlParser did not complete (status: ${emlStatus}, job: ${emlJobId})`);

const emlReport = await jobReport(emlJobId);

// ── STEP 2: email metadata + observables ───────────────────────────
const H     = (emlReport.full && emlReport.full.headers) || {};
const first = (v) => (Array.isArray(v) ? (v[0] || '') : (v || ''));

const email = {
  subject:       first(H.subject),
  from:          first(H.from),
  to:            first(H.to),
  reply_to:      first(H['reply-to']),
  return_path:   first(H['return-path']),
  date:          first(H.date),
  received_hops: Array.isArray(H.received) ? H.received.length : 0,
  attachments:   ((emlReport.full && emlReport.full.attachments) || []).length,
  eml_job_id:    emlJobId,
};

const OBSERVABLES = (emlReport.artifacts || []).map(a => ({
  dataType: a.dataType,
  data: a.data,
  tags: a.tags || [],
}));

// ── STEP 3: plan (dedup + routing + cap) ───────────────────────────
const seen  = new Set();
const tasks = [];
for (const obs of OBSERVABLES) {
  const key = `${obs.dataType}:${String(obs.data).toLowerCase()}`;
  if (seen.has(key)) continue;
  seen.add(key);

  let route = ROUTING[obs.dataType] || [];
  if (!INCLUDE_SLOW) route = route.filter(n => !(REGISTRY[n] && REGISTRY[n].slow));
  route = route.filter(n => REGISTRY[n]).slice(0, MAX_ANALYZERS_PER_OBS);

  for (const azName of route) tasks.push({ azName, obs });
}

// ── STEP 4: enrich one observable with one analyzer (isolated) ─────
async function enrichOne(azName, obs) {
  const base = { analyzer: azName, obs: obs.data, dataType: obs.dataType, taxonomies: [], rank: 0 };
  try {
    const run = await http({
      method: 'POST',
      url: `${CORTEX}/api/analyzer/${REGISTRY[azName].id}/run`,
      headers: jsonHeaders,
      body: { dataType: obs.dataType, data: obs.data, tlp: TLP },
      json: true,
    });
    const st = await poll(run.id, PER_ANALYZER_TIMEOUT_MS);
    if (st !== 'Success') return { ...base, status: st };

    const rep = await jobReport(run.id);
    const tax = (rep.summary && rep.summary.taxonomies) || [];
    let rank = 0;
    for (const t of tax) if (bearsVerdict(t)) rank = Math.max(rank, LEVEL_RANK[t.level] ?? 0);

    return {
      ...base,
      status: 'Success',
      rank,
      taxonomies: tax.map(t => ({ level: t.level, ns: t.namespace, pred: t.predicate, val: t.value })),
    };
  } catch (e) {
    return { ...base, status: 'Error', error: errText(e) };
  }
}

// ── STEP 5: bounded-parallel execution ─────────────────────────────
const results = [];
for (let i = 0; i < tasks.length; i += CONCURRENCY) {
  const batch   = tasks.slice(i, i + CONCURRENCY);
  const settled = await Promise.allSettled(batch.map(t => enrichOne(t.azName, t.obs)));
  for (let j = 0; j < settled.length; j++) {
    const s = settled[j];
    results.push(
      s.status === 'fulfilled'
        ? s.value
        : {
            analyzer: batch[j].azName, obs: batch[j].obs.data, dataType: batch[j].obs.dataType,
            status: 'Error', error: String(s.reason), taxonomies: [], rank: 0,
          }
    );
  }
}

// ── STEP 6: roll up into a single verdict ──────────────────────────
const byObservable = {};
const reasons = [];
let worst = 0, ran = 0, failed = 0;

for (const r of results) {
  if (r.status === 'Success') ran++; else failed++;
  worst = Math.max(worst, r.rank);

  for (const t of r.taxonomies) {
    if (bearsVerdict(t) && (LEVEL_RANK[t.level] ?? 0) >= 2) reasons.push(`${r.obs} → ${t.ns}:${t.pred}=${t.val}`);
  }

  const o = byObservable[r.obs] = byObservable[r.obs] || { dataType: r.dataType, verdict: 'info', analyzers: {} };
  o.analyzers[r.analyzer] = {
    status: r.status,
    level: RANK_LEVEL[r.rank],
    taxonomies: r.taxonomies,
    ...(r.error ? { error: r.error } : {}),
  };
  o.verdict = RANK_LEVEL[Math.max(LEVEL_RANK[o.verdict] ?? 0, r.rank)];
}

return [{
  json: {
    email,
    verdict: RANK_LEVEL[worst],
    verdict_reason: [...new Set(reasons)],
    observable_count: OBSERVABLES.length,
    jobs_planned: tasks.length,
    analyzers_run: ran,
    analyzers_failed: failed,
    concurrency: CONCURRENCY,
    observables: byObservable,
    duration_ms: Date.now() - T0,
    started_utc: new Date(T0).toISOString(),
  },
}];

// ═══════════════════════════════════════════════════════════════════
//  PHISHING SIGNAL SCORING
//  Reads the raw email + Cortex verdict, applies reputation-independent
//  detection signals (brand lookalike, auth failures, header mismatches,
//  link deception, lure language), and produces an L1 disposition hint.
// ═══════════════════════════════════════════════════════════════════
const T0 = Date.now();

const CORTEX = 'http://10.10.10.10:9001';
const AUTH   = 'Bearer ' + 'PASTE_FULL_MDR_ADMIN_KEY';  

const BRANDS = [
  'paypal','microsoft','office365','outlook','onedrive','sharepoint','google','gmail',
  'apple','icloud','amazon','netflix','facebook','instagram','linkedin','whatsapp',
  'dhl','fedex','ups','aramex','dropbox','adobe','docusign','zoom','binance','coinbase',
  'wetransfer','booking','airbnb','steam','bankofamerica','hsbc','citibank',
];

const URGENCY = [
  'urgent','immediately','suspend','suspended','limited','locked','unusual activity',
  'action required','verify your','confirm your','within 24 hours','final notice',
  'unauthorized','will be closed','expire','expired','click here','update your',
  'security alert','account has been',
];

const CRED_PATH = [
  'verify','login','signin','sign-in','secure','account','update','confirm',
  'password','auth','recover','unlock','billing','validate','session',
];

const RISKY_EXT = [
  'exe','scr','js','jse','vbs','vbe','hta','wsf','lnk','iso','img','msi','bat','cmd','ps1',
  'docm','xlsm','pptm','jar','html','htm','svg',
];

const MULTI_TLD = [
  'co.uk','org.uk','gov.uk','ac.uk','com.au','co.jp','com.br','co.in','com.tr',
  'com.mx','co.za','com.sa','com.eg','com.jo','edu.jo','gov.jo','net.au','co.nz',
];

// ── helpers ────────────────────────────────────────────────────────
const http = this.helpers.httpRequest.bind(this);
const headers = { Authorization: AUTH, 'Content-Type': 'application/json', Accept: 'application/json' };

function registrable(host) {
  if (!host) return '';
  const h = String(host).toLowerCase().replace(/^\.+|\.+$/g, '');
  const parts = h.split('.');
  if (parts.length < 2) return h;
  const last2 = parts.slice(-2).join('.');
  if (MULTI_TLD.includes(last2) && parts.length >= 3) return parts.slice(-3).join('.');
  return last2;
}

function hostOfUrl(u) {
  try {
    const m = String(u).match(/^[a-z][a-z0-9+.-]*:\/\/([^/?#\s]+)/i);
    if (!m) return '';
    return m[1].replace(/^[^@]*@/, '').replace(/:\d+$/, '').toLowerCase();
  } catch (e) { return ''; }
}

function domainOfAddress(addr) {
  const m = String(addr || '').match(/@([A-Za-z0-9.-]+)/);
  return m ? m[1].toLowerCase() : '';
}

// Collapse common homoglyph substitutions so paypa1 → paypal
function deglyph(s) {
  return String(s).toLowerCase()
    .replace(/[0]/g, 'o').replace(/[1|!]/g, 'l').replace(/[3]/g, 'e')
    .replace(/[4]/g, 'a').replace(/[5]/g, 's').replace(/[7]/g, 't')
    .replace(/rn/g, 'm').replace(/vv/g, 'w')
    .replace(/[^a-z]/g, '');
}

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  if (!m) return n; if (!n) return m;
  let prev = Array.from({ length: n + 1 }, (_, i) => i);
  for (let i = 1; i <= m; i++) {
    const cur = [i];
    for (let j = 1; j <= n; j++) {
      cur[j] = Math.min(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1));
    }
    prev = cur;
  }
  return prev[n];
}

// Returns the brand a domain is imitating, or null when it is the real thing
function impersonatedBrand(host) {
  const reg = registrable(host);
  if (!reg) return null;
  const label = reg.split('.')[0];
  const norm  = deglyph(label);
  const full  = deglyph(host);
  for (const b of BRANDS) {
    const legit = reg === `${b}.com` || reg.startsWith(`${b}.`) ;
    if (legit) return null;
    if (norm === b && label !== b) return b;                 // paypa1 → paypal
    if (levenshtein(norm, b) <= 1 && Math.abs(norm.length - b.length) <= 1 && norm !== b) return b;
    if (full.includes(b)) return b;                          // paypal-secure-login.tk
  }
  return null;
}

// ── input: enrichment result from the previous node ────────────────
const prev = $input.first().json;
const emlJobId = prev && prev.eml_job_id ? prev.eml_job_id : (prev.email && prev.email.eml_job_id);
if (!emlJobId) throw new Error('No eml_job_id on the incoming item — run the enrichment node first.');

const rep = await http({ method: 'GET', url: `${CORTEX}/api/job/${emlJobId}/report`, headers, json: true });
let emlReport = rep.report || {};
if (typeof emlReport === 'string') emlReport = JSON.parse(emlReport);

const full = emlReport.full || {};
const raw  = String(full.raw_email || '');
const H    = full.headers || {};
const one  = (v) => (Array.isArray(v) ? (v[0] || '') : (v || ''));

const fromRaw     = one(H.from);
const fromDomain  = domainOfAddress(fromRaw);
const replyTo     = one(H['reply-to']);
const returnPath  = one(H['return-path']);
const subject     = one(H.subject);
const displayName = (fromRaw.match(/^\s*"?([^"<]+)"?\s*</) || [, ''])[1].trim();

const urls = (emlReport.artifacts || [])
  .filter(a => a.dataType === 'url')
  .map(a => a.data);

const attachments = (full.attachments || []).map(a => a.filename || a.name || '');

// ── signals ────────────────────────────────────────────────────────
const signals = [];
const add = (id, weight, detail) => signals.push({ id, weight, detail });

// 1. sender domain imitating a known brand
const senderBrand = impersonatedBrand(fromDomain);
if (senderBrand) add('sender_brand_lookalike', 40,
  `Sender domain "${fromDomain}" imitates "${senderBrand}"`);

// 2. brand in display name but not in the actual domain
for (const b of BRANDS) {
  if (deglyph(displayName).includes(b) && !registrable(fromDomain).includes(b)) {
    add('display_name_brand_mismatch', 25,
      `Display name claims "${displayName}" but domain is "${fromDomain}"`);
    break;
  }
}

// 3. SPF / DKIM / DMARC results parsed from the raw headers
const authLine = (raw.match(/^Authentication-Results:[\s\S]*?(?=\r?\n[A-Za-z-]+:)/mi) || [''])[0];
if (authLine) {
  const spf   = (authLine.match(/spf=(\w+)/i)   || [, ''])[1].toLowerCase();
  const dkim  = (authLine.match(/dkim=(\w+)/i)  || [, ''])[1].toLowerCase();
  const dmarc = (authLine.match(/dmarc=(\w+)/i) || [, ''])[1].toLowerCase();
  if (['fail','softfail','none'].includes(spf))  add('spf_not_pass', 20,  `SPF result: ${spf}`);
  if (['fail','none'].includes(dkim))            add('dkim_not_pass', 15, `DKIM result: ${dkim}`);
  if (['fail','none'].includes(dmarc))           add('dmarc_not_pass', 25, `DMARC result: ${dmarc}`);
} else {
  add('no_auth_results', 10, 'No Authentication-Results header present');
}

// 4. envelope / header mismatches
const rpDomain = domainOfAddress(returnPath);
if (rpDomain && fromDomain && registrable(rpDomain) !== registrable(fromDomain)) {
  add('return_path_mismatch', 15, `Return-Path (${rpDomain}) differs from From (${fromDomain})`);
}
const rtDomain = domainOfAddress(replyTo);
if (rtDomain && fromDomain && registrable(rtDomain) !== registrable(fromDomain)) {
  add('reply_to_mismatch', 15, `Reply-To (${rtDomain}) differs from From (${fromDomain})`);
}

// 5. link deception — anchor text pointing somewhere else
const anchorRe = /<a\s[^>]*href\s*=\s*["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
let m;
while ((m = anchorRe.exec(raw)) !== null) {
  const href = m[1];
  const text = m[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  const hrefHost = registrable(hostOfUrl(href));
  const textHost = registrable(hostOfUrl(text) || (text.match(/\b[a-z0-9.-]+\.[a-z]{2,}\b/i) || [''])[0]);
  if (textHost && hrefHost && textHost !== hrefHost) {
    add('anchor_text_mismatch', 25, `Link text shows "${textHost}" but points to "${hrefHost}"`);
    break;
  }
  const tBrand = BRANDS.find(b => deglyph(text).includes(b));
  if (tBrand && hrefHost && !hrefHost.includes(tBrand)) {
    add('anchor_brand_mismatch', 25, `Link text mentions "${tBrand}" but points to "${hrefHost}"`);
    break;
  }
}

// 6. URL-level indicators
let credHit = false, ipHit = false, punyHit = false, offSiteHit = false, brandUrlHit = false;
for (const u of urls) {
  const host = hostOfUrl(u);
  const reg  = registrable(host);
  const path = String(u).replace(/^[a-z]+:\/\/[^/]+/i, '').toLowerCase();

  if (!credHit && CRED_PATH.some(k => path.includes(k))) {
    add('credential_path', 15, `URL path suggests credential capture: ${u.slice(0, 90)}`); credHit = true;
  }
  if (!ipHit && /^\d{1,3}(\.\d{1,3}){3}$/.test(host)) {
    add('ip_literal_url', 30, `URL uses a bare IP address: ${host}`); ipHit = true;
  }
  if (!punyHit && host.includes('xn--')) {
    add('punycode_url', 30, `Punycode (internationalised) domain: ${host}`); punyHit = true;
  }
  if (!brandUrlHit) {
    const ub = impersonatedBrand(host);
    if (ub) { add('url_brand_lookalike', 35, `Link domain "${reg}" imitates "${ub}"`); brandUrlHit = true; }
  }
  if (!offSiteHit && fromDomain && reg && reg !== registrable(fromDomain)) {
    add('link_offsite_from_sender', 5, `Link host "${reg}" differs from sender domain`); offSiteHit = true;
  }
}

// 7. lure language
const subjLower = subject.toLowerCase();
const bodyLower = raw.toLowerCase();
const subjHits  = URGENCY.filter(k => subjLower.includes(k));
const bodyHits  = URGENCY.filter(k => bodyLower.includes(k));
if (subjHits.length) add('urgency_subject', 12, `Urgency language in subject: ${subjHits.slice(0, 3).join(', ')}`);
else if (bodyHits.length) add('urgency_body', 8, `Urgency language in body: ${bodyHits.slice(0, 3).join(', ')}`);

// 8. attachments
for (const f of attachments) {
  const ext = (String(f).split('.').pop() || '').toLowerCase();
  if (RISKY_EXT.includes(ext)) { add('risky_attachment', 35, `Attachment with risky extension: ${f}`); break; }
}

// 9. the Cortex verdict itself
const cortexVerdict = prev.verdict || 'info';
if (cortexVerdict === 'malicious')       add('cortex_malicious', 60, 'Threat intelligence flagged an observable as malicious');
else if (cortexVerdict === 'suspicious') add('cortex_suspicious', 30, 'Threat intelligence flagged an observable as suspicious');

// ── final score ────────────────────────────────────────────────────
const score = signals.reduce((s, x) => s + x.weight, 0);

let risk, disposition_hint;
if (score >= 70)      { risk = 'high';   disposition_hint = 'Likely True Positive — contain and escalate'; }
else if (score >= 40) { risk = 'medium'; disposition_hint = 'Suspicious — analyst review required'; }
else if (score >= 15) { risk = 'low';    disposition_hint = 'Weak indicators — review, likely benign'; }
else                  { risk = 'clean';  disposition_hint = 'Likely False Positive — close with note'; }

return [{
  json: {
    ...prev,
    scoring: {
      score,
      risk,
      disposition_hint,
      signal_count: signals.length,
      signals: signals.sort((a, b) => b.weight - a.weight),
      cortex_verdict: cortexVerdict,
      scored_in_ms: Date.now() - T0,
    },
  },
}];
